class SMACrossoverStrategy(Strategy):
    def init(self, params):
        self.fast_window = max(1, int(params.get("fast_window", 20)))
        self.slow_window = max(self.fast_window + 1, int(params.get("slow_window", 50)))
        self.quantity = float(params.get("quantity", 10))
        self.closes = []

    def next(self, row, portfolio):
        symbol = row["symbol"]
        close = float(row["close"])
        self.closes.append(close)

        if len(self.closes) < self.slow_window:
            return None

        fast_average = sum(self.closes[-self.fast_window:]) / self.fast_window
        slow_average = sum(self.closes[-self.slow_window:]) / self.slow_window
        position = portfolio.get_position(symbol)

        if fast_average > slow_average and position.quantity <= 0:
            return Signal(
                symbol=symbol,
                side="buy",
                quantity=self.quantity,
                reason="Fast SMA crossed above slow SMA",
            )

        if fast_average < slow_average and position.quantity > 0:
            return Signal(
                symbol=symbol,
                side="sell",
                quantity=position.quantity,
                reason="Fast SMA crossed below slow SMA",
            )

        return None

