class RSIMeanReversionStrategy(Strategy):
    def init(self, params):
        self.period = max(2, int(params.get("period", 14)))
        self.oversold = float(params.get("oversold", 30))
        self.overbought = float(params.get("overbought", 70))
        self.quantity = float(params.get("quantity", 10))
        self.closes = []

    def next(self, row, portfolio):
        symbol = row["symbol"]
        close = float(row["close"])
        self.closes.append(close)

        if len(self.closes) <= self.period:
            return None

        gains = []
        losses = []
        start = len(self.closes) - self.period
        for index in range(start, len(self.closes)):
            change = self.closes[index] - self.closes[index - 1]
            if change >= 0:
                gains.append(change)
            else:
                losses.append(abs(change))

        average_gain = sum(gains) / self.period
        average_loss = sum(losses) / self.period
        rsi = 100.0 if average_loss == 0 else 100.0 - (100.0 / (1.0 + average_gain / average_loss))
        position = portfolio.get_position(symbol)

        if rsi < self.oversold and position.quantity <= 0:
            return Signal(
                symbol=symbol,
                side="buy",
                quantity=self.quantity,
                reason="RSI moved below oversold threshold",
            )

        if rsi > self.overbought and position.quantity > 0:
            return Signal(
                symbol=symbol,
                side="sell",
                quantity=position.quantity,
                reason="RSI moved above overbought threshold",
            )

        return None

