class MomentumStrategy(Strategy):
    def init(self, params):
        self.lookback = max(1, int(params.get("lookback", 20)))
        self.threshold = float(params.get("threshold", 0.03))
        self.quantity = float(params.get("quantity", 10))
        self.closes = []

    def next(self, row, portfolio):
        symbol = row["symbol"]
        close = float(row["close"])
        self.closes.append(close)

        if len(self.closes) <= self.lookback:
            return None

        reference_close = self.closes[-self.lookback - 1]
        if reference_close == 0:
            return None

        momentum = close / reference_close - 1.0
        position = portfolio.get_position(symbol)

        if momentum >= self.threshold and position.quantity <= 0:
            return Signal(
                symbol=symbol,
                side="buy",
                quantity=self.quantity,
                reason="Lookback momentum exceeded threshold",
            )

        if momentum <= 0 and position.quantity > 0:
            return Signal(
                symbol=symbol,
                side="sell",
                quantity=position.quantity,
                reason="Momentum faded below zero",
            )

        return None
